    test_feature_builder_computes_drawdown_recovery_features = LegacyPipelineTest.test_feature_builder_computes_drawdown_recovery_features
    test_feature_builder_computes_return_stability_features = LegacyPipelineTest.test_feature_builder_computes_return_stability_features
