    test_manager_tenure_prefers_monthly_manager_assignment = LegacyPipelineTest.test_manager_tenure_prefers_monthly_manager_assignment
    test_manager_tenure_falls_back_or_clamps_on_bad_manager_start_month = LegacyPipelineTest.test_manager_tenure_falls_back_or_clamps_on_bad_manager_start_month
