    test_factor_evaluation_respects_factor_direction = LegacyPipelineTest.test_factor_evaluation_respects_factor_direction
    test_factor_evaluation_skips_months_without_next_return = LegacyPipelineTest.test_factor_evaluation_skips_months_without_next_return
    test_factor_evaluation_distribution_and_correlation_handle_constant_and_missing_values = LegacyPipelineTest.test_factor_evaluation_distribution_and_correlation_handle_constant_and_missing_values
